#include <iostream>
#include <initializer_list>
#include <string>

class IntBag {
    int data_[16]{};
    int count_{0};
public:
    IntBag() = default;

    IntBag(std::initializer_list<int> list) {
        for (int v : list)
            data_[count_++] = v;
    }

    void add(int v) {
        data_[count_++] = v;
    }

    int size() const { return count_; }

    int get(int i) const {
        return data_[i];
    }
};

int main() {
    int n{};
    std::cin >> n;
